#!/usr/bin/env node
// SOURCING: none. Pure logic, no upstream component applies.
// Writes src/styles/token-manifest.json from the register files (X2). Run it
// after adding a token to a register; the diff it produces is the review.

import { writeFileSync } from 'node:fs';
import path from 'node:path';
import { buildManifest, MANIFEST_PATH, appRoot } from './token-manifest-lib.mjs';

const manifest = buildManifest();
const document = {
  $comment:
    'Generated by scripts/generate-token-manifest.mjs (HANDOFF-CONSOLE-DIMENSIONALITY X2). Every --ij-*, --rec-* and --gy-* name the console emits, the register file that owns it, and that file\'s provenance. Components may not mint register tokens; scripts/check-token-manifest.mjs fails on any drift between this file and the registers.',
  tokens: manifest,
};

writeFileSync(MANIFEST_PATH, `${JSON.stringify(document, null, 2)}\n`);
console.log(
  `Token manifest: wrote ${Object.keys(manifest).length} tokens to ${path.relative(appRoot, MANIFEST_PATH)}.`,
);
